for (const id of ["en", "ko", "ar", "de", "fr", "la"]) {
  for (const key of Object.keys(zh)) {
    if (dictionaries[id]?.[key] === zh[key] && dictionaries.en?.[key] !== zh[key]) {
      dictionaries[id][key] = dictionaries.en[key];
    }
  }
}

let locale = normalizeLocale(localStorage.getItem(STORE_KEY) || "zh-CN");

export function getLocale() {
  return locale;
}

export function setLocale(next) {
  locale = normalizeLocale(next);
  localStorage.setItem(STORE_KEY, locale);
  applyDocumentLocale();
}

export function t(key, values = {}) {
  const template = dictionaries[locale]?.[key] ?? dictionaries.en?.[key] ?? zh[key] ?? key;
  return template.replace(/\{(\w+)\}/g, (_, name) => values[name] ?? "");
}

export function applyI18n(root = document) {
  applyDocumentLocale();
  root.querySelectorAll("[data-i18n]").forEach((node) => {
    node.textContent = t(node.dataset.i18n);
  });
  root.querySelectorAll("[data-i18n-html]").forEach((node) => {
    node.innerHTML = t(node.dataset.i18nHtml);
  });
  [
    ["data-i18n-title", "title"],
    ["data-i18n-aria-label", "aria-label"],
    ["data-i18n-placeholder", "placeholder"],
    ["data-i18n-data-title", "data-title"],
    ["data-i18n-data-desc", "data-desc"],
  ].forEach(([dataAttr, attr]) => {
    root.querySelectorAll(`[${dataAttr}]`).forEach((node) => {
      node.setAttribute(attr, t(node.getAttribute(dataAttr)));
    });
  });
}

export function fillLocaleSelect(select) {
  if (!select) return;
  select.innerHTML = "";
  for (const item of LOCALES) {
    const option = document.createElement("option");
    option.value = item.id;
    option.textContent = item.name;
    select.appendChild(option);
  }
  select.value = locale;
}

function normalizeLocale(next) {
  return LOCALES.some((item) => item.id === next) ? next : "zh-CN";
}

function applyDocumentLocale() {
  document.documentElement.lang = locale;
  document.documentElement.dir = RTL.has(locale) ? "rtl" : "ltr";
}
